SELECT [CreditoGrigliaAgenti-step0].[Salesperson Code], [CreditoGrigliaAgenti-step0].Salesperson, [CreditoGrigliaAgenti-step0].[Sell-to Customer No_], [CreditoGrigliaAgenti-step0].[Sell-to Name], [CreditoGrigliaAgenti-step0].City, [CreditoGrigliaAgenti-step0].[Current Risk], Customer.[Risk Rating], [CreditoGrigliaAgenti-step0].[trademark code], [CreditoGrigliaAgenti-step0].[season code], Customer.[purchase group], [CreditoGrigliaAgenti-step0].[Payment Method Code], [CreditoGrigliaAgenti-step0].[Payment Terms Code], [CreditoGrigliaAgenti-step0].ScontoFattura, [CreditoGrigliaAgenti-step0].ContoVendita, [CreditoGrigliaAgenti-step0].PercentualeDirittoAlReso, [CreditoGrigliaAgenti-step0].PairsSold, [CreditoGrigliaAgenti-step0].ValueSold_, [CreditoGrigliaAgenti-step0].ValueSoldVAT_, Round((Round(IIf(IsNull([AnalisiCredito-step1-datiSaldoClienti].[No_]),0,[SaldoD])*100)/100+Round(IIf(IsNull([AnalisiCredito-step1-datiSaldoExtraClienti].[No_]),0,[SaldoDExtra])*100)/100)*100)/100 AS Balance, [CreditoGrigliaAgenti-step0].[requested delivery date], IIf([marchiagente]<>[marchituttigliagenti],"****","") AS AltreAgenzie, IIf([Blocked for Assignments]=1,"BLOCKED","") AS Blocked, [CreditoGrigliaAgenti-step0].NOTE
FROM (([CreditoGrigliaAgenti-step0] INNER JOIN ((Customer LEFT JOIN [AnalisiCredito-step1-datiSaldoClienti] ON Customer.No_ = [AnalisiCredito-step1-datiSaldoClienti].No_) LEFT JOIN [AnalisiCredito-step1-datiSaldoExtraClienti] ON Customer.No_ = [AnalisiCredito-step1-datiSaldoExtraClienti].No_) ON [CreditoGrigliaAgenti-step0].[Sell-to Customer No_] = Customer.No_) LEFT JOIN [CreditoGrigliaAgenti-step0b-contaMarchiAgente] ON Customer.No_ = [CreditoGrigliaAgenti-step0b-contaMarchiAgente].[Sell-to Customer No_]) LEFT JOIN [CreditoGrigliaAgenti-step0b-contaMarchiTuttiGliAgenti] ON Customer.No_ = [CreditoGrigliaAgenti-step0b-contaMarchiTuttiGliAgenti].[Sell-to Customer No_]
ORDER BY [CreditoGrigliaAgenti-step0].[Sell-to Name];

